 29Ôćĺ	if (!cliCallback || !state) return null;
 30Ôćĺ	try {
 31Ôćĺ		const url = new URL(cliCallback);
 32Ôćĺ		if (url.hostname !== "127.0.0.1") return null;
 33Ôćĺ	} catch {
