 15Ôćĺ/**
 16Ôćĺ * Get learnings feed from compound:feedback sessions
 17Ôćĺ */
 18Ôćĺexport async function getLearningsFeed(
 19Ôćĺ	orgId: string,
 20Ôćĺ	params: {
 21Ôćĺ		days?: number;
 22Ôćĺ		user_id?: string;
 23Ôćĺ		project_path?: string;
 24Ôćĺ		limit?: number;
 25Ôćĺ		offset?: number;
 26Ôćĺ	} = {},
 27Ôćĺ): Promise<LearningEntry[]> {
 28Ôćĺ	const { days = 30, user_id, project_path, limit = 50, offset = 0 } = params;
 29Ôćĺ
 30Ôćĺ	const org = escapeString(orgId);
 31Ôćĺ	const d = Number(days);
 32Ôćĺ	const lim = Number(limit);
 33Ôćĺ	const off = Number(offset);
 34Ôćĺ
 35Ôćĺ	let filters = `last_interaction_date >= now64(3) - INTERVAL ${d} DAY
 36Ôćĺ    AND has(slash_commands, 'compound:feedback')
 37Ôćĺ    AND organization_id = '${org}'`;
 38Ôćĺ
 39Ôćĺ	if (user_id) {
 40Ôćĺ		filters += `\n    AND user_id = '${escapeString(user_id)}'`;
 41Ôćĺ	}
 42Ôćĺ	if (project_path) {
 43Ôćĺ		filters += `\n    AND project_path = '${escapeString(project_path)}'`;
 44Ôćĺ	}
 45Ôćĺ
 46Ôćĺ	const query = `
 47Ôćĺ    WITH
 48Ôćĺ      feedback_data AS (
 49Ôćĺ        SELECT
 50Ôćĺ          session_id,
 51Ôćĺ          user_id,
 52Ôćĺ          last_interaction_date,
 53Ôćĺ          project_path,
 54Ôćĺ          organization_id,
 55Ôćĺ          repository,
 56Ôćĺ          subagents,
 57Ôćĺ          skills,
 58Ôćĺ          slash_commands,
 59Ôćĺ          content
 60Ôćĺ        FROM rudel.session_analytics
 61Ôćĺ        WHERE ${filters}
 62Ôćĺ      )
 63Ôćĺ    SELECT
 64Ôćĺ      session_id,
 65Ôćĺ      user_id,
 66Ôćĺ      formatDateTime(last_interaction_date, '%Y-%m-%dT%H:%i:%SZ') as created_at,
 67Ôćĺ      'feedback' as type,
 68Ôćĺ      if(
 69Ôćĺ        position(content, '<command-name>/compound:feedback</command-name>') > 0
 70Ôćĺ        AND position(content, '<command-args>', position(content, '<command-name>/compound:feedback</command-name>')) > 0
 71Ôćĺ        AND position(content, '</command-args>', position(content, '<command-name>/compound:feedback</command-name>')) > 0,
 72Ôćĺ        trimBoth(
 73Ôćĺ          substring(
 74Ôćĺ            content,
 75Ôćĺ            position(content, '<command-args>', position(content, '<command-name>/compound:feedback</command-name>')) + 14,
 76Ôćĺ            least(
 77Ôćĺ              position(content, '</command-args>', position(content, '<command-name>/compound:feedback</command-name>'))
 78Ôćĺ              - position(content, '<command-args>', position(content, '<command-name>/compound:feedback</command-name>'))
 79Ôćĺ              - 14,
 80Ôćĺ              5000
 81Ôćĺ            )
 82Ôćĺ          )
 83Ôćĺ        ),
 84Ôćĺ        concat('Feedback session in ', if(repository != '', repository, project_path))
 85Ôćĺ      ) as content,
 86Ôćĺ      'project' as scope,
 87Ôćĺ      [] as tags,
 88Ôćĺ      project_path,
 89Ôćĺ      organization_id,
 90Ôćĺ      repository,
 91Ôćĺ      mapKeys(subagents) as subagents,
 92Ôćĺ      skills,
 93Ôćĺ      arrayFilter(x -> x != 'compound:feedback', slash_commands) as other_commands
 94Ôćĺ    FROM feedback_data
 95Ôćĺ    ORDER BY last_interaction_date DESC
 96Ôćĺ    LIMIT ${lim}
 97Ôćĺ    OFFSET ${off}
 98Ôćĺ  `;
 99Ôćĺ
100Ôćĺ	return queryClickhouse<LearningEntry>(query);
101Ôćĺ}
