103Ôćĺ/**
104Ôćĺ * Get learnings feed statistics
105Ôćĺ */
106Ôćĺexport async function getLearningsFeedStats(
107Ôćĺ	orgId: string,
108Ôćĺ	params: {
109Ôćĺ		days?: number;
110Ôćĺ		user_id?: string;
111Ôćĺ		project_path?: string;
112Ôćĺ	} = {},
113Ôćĺ): Promise<LearningsFeedStats> {
114Ôćĺ	const { days = 30, user_id, project_path } = params;
115Ôćĺ	const org = escapeString(orgId);
116Ôćĺ	const d = Number(days);
117Ôćĺ
118Ôćĺ	let filters = `last_interaction_date >= now64(3) - INTERVAL ${d} DAY
119Ôćĺ    AND has(slash_commands, 'compound:feedback')
120Ôćĺ    AND organization_id = '${org}'`;
121Ôćĺ
122Ôćĺ	if (user_id) {
123Ôćĺ		filters += `\n    AND user_id = '${escapeString(user_id)}'`;
124Ôćĺ	}
125Ôćĺ	if (project_path) {
126Ôćĺ		filters += `\n    AND project_path = '${escapeString(project_path)}'`;
127Ôćĺ	}
128Ôćĺ
129Ôćĺ	const statsQuery = `
130Ôćĺ    SELECT
131Ôćĺ      count() as total_learnings,
132Ôćĺ      uniq(user_id) as unique_users,
133Ôćĺ      uniq(project_path) as unique_projects
134Ôćĺ    FROM rudel.session_analytics
135Ôćĺ    WHERE ${filters}
136Ôćĺ  `;
137Ôćĺ
138Ôćĺ	const timeSeriesQuery = `
139Ôćĺ    SELECT
140Ôćĺ      toDate(last_interaction_date) as date,
141Ôćĺ      count() as count
142Ôćĺ    FROM rudel.session_analytics
143Ôćĺ    WHERE ${filters}
144Ôćĺ    GROUP BY date
145Ôćĺ    ORDER BY date DESC
146Ôćĺ  `;
147Ôćĺ
148Ôćĺ	const [statsData, timeSeriesData] = await Promise.all([
149Ôćĺ		queryClickhouse<{
150Ôćĺ			total_learnings: number;
151Ôćĺ			unique_users: number;
152Ôćĺ			unique_projects: number;
153Ôćĺ		}>(statsQuery),
154Ôćĺ		queryClickhouse<{ date: string; count: number }>(timeSeriesQuery),
155Ôćĺ	]);
156Ôćĺ
157Ôćĺ	const stats = statsData[0] || {
158Ôćĺ		total_learnings: 0,
159Ôćĺ		unique_users: 0,
160Ôćĺ		unique_projects: 0,
161Ôćĺ	};
162Ôćĺ
163Ôćĺ	return {
164Ôćĺ		...stats,
165Ôćĺ		learnings_by_day: timeSeriesData,
166Ôćĺ	};
167Ôćĺ}
