207Ôćĺ/**
208Ôćĺ * Get learnings trend over time with splits by user_id or repository
209Ôćĺ */
210Ôćĺexport async function getLearningsTrend(
211Ôćĺ	orgId: string,
212Ôćĺ	params: {
213Ôćĺ		days?: number;
214Ôćĺ		split_by: "user_id" | "repository";
215Ôćĺ	},
216Ôćĺ): Promise<LearningsTrendDataPoint[]> {
217Ôćĺ	const { days = 30, split_by } = params;
218Ôćĺ	const org = escapeString(orgId);
219Ôćĺ	const d = Number(days);
220Ôćĺ
221Ôćĺ	const splitColumn =
222Ôćĺ		split_by === "repository"
223Ôćĺ			? "if(repository != '', repository, 'Unknown')"
224Ôćĺ			: "user_id";
225Ôćĺ
226Ôćĺ	const query = `
227Ôćĺ    SELECT
228Ôćĺ      toDate(last_interaction_date) as date,
229Ôćĺ      ${splitColumn} as split_key,
230Ôćĺ      count() as count
231Ôćĺ    FROM rudel.session_analytics
232Ôćĺ    WHERE last_interaction_date >= now64(3) - INTERVAL ${d} DAY
233Ôćĺ      AND has(slash_commands, 'compound:feedback')
234Ôćĺ      AND organization_id = '${org}'
235Ôćĺ    GROUP BY date, split_key
236Ôćĺ    ORDER BY date ASC, split_key ASC
237Ôćĺ  `;
238Ôćĺ
239Ôćĺ	const rawData = await queryClickhouse<{
240Ôćĺ		date: string;
241Ôćĺ		split_key: string;
242Ôćĺ		count: number;
243Ôćĺ	}>(query);
244Ôćĺ
245Ôćĺ	// Transform data into chart-friendly format
246Ôćĺ	const dataByDate = new Map<string, Record<string, number>>();
247Ôćĺ	const allSplitKeys = new Set<string>();
248Ôćĺ
249Ôćĺ	rawData.forEach((row) => {
250Ôćĺ		if (!dataByDate.has(row.date)) {
251Ôćĺ			dataByDate.set(row.date, {});
252Ôćĺ		}
253Ôćĺ		const entry = dataByDate.get(row.date);
254Ôćĺ		if (entry) entry[row.split_key] = row.count;
255Ôćĺ		allSplitKeys.add(row.split_key);
256Ôćĺ	});
257Ôćĺ
258Ôćĺ	const chartData: LearningsTrendDataPoint[] = Array.from(dataByDate.entries())
259Ôćĺ		.map(([date, counts]) => {
260Ôćĺ			const dataPoint: LearningsTrendDataPoint = { date };
261Ôćĺ			allSplitKeys.forEach((key) => {
262Ôćĺ				dataPoint[key] = counts[key] || 0;
263Ôćĺ			});
264Ôćĺ			return dataPoint;
265Ôćĺ		})
266Ôćĺ		.sort((a, b) => (a.date as string).localeCompare(b.date as string));
267Ôćĺ
268Ôćĺ	return chartData;
269Ôćĺ}
